class Solution {
    void inOrder(Node* root){
        if(root == NULL)
          return;
        inOrder(root -> left);
        cout << root->val << " ";
        inOrder(root -> right);
    }
  public:
    void printNodes(Node* root) {
        inOrder(root);
    }
};

