code.Java:
class Solution {
    public static void printNodes(Node root) {
        inOrder(root);
    }

    public static void inOrder(Node root) {
        if (root == null) return;
        inOrder(root.left);
        System.out.print(root.val + " ");
        inOrder(root.right);
    }
}

